          _f: {
            name: 'test',
            ref: {
              setCustomValidity,
              reportValidity,
              name: 'test',
              value: '',
            },
            value: '',
            required: true,
            mount: true,
          },
        },
        new Set(),
        {
          test: '',
        },
        false,
        true,
      );

      expect(setCustomValidity).toHaveBeenCalledWith('');
      expect(reportValidity).toHaveBeenCalled();
    });

    it('should invoke setCustomValidity for invalid input with its message', () => {
      const setCustomValidity = jest.fn();
      const reportValidity = jest.fn();

      validateField(
        {
          _f: {
            name: 'test',
            ref: {
              setCustomValidity,
              reportValidity,
              name: 'test',
              value: '',
            },
            value: '',
            required: 'something is wrong',
            mount: true,
          },
        },
        new Set(),
        {
          test: '',
        },
        false,
        true,
      );

      expect(setCustomValidity).toHaveBeenCalledWith('something is wrong');
      expect(reportValidity).toHaveBeenCalled();
    });

    it('should invoke setCustomValidity with empty string for a valid input', () => {
      const setCustomValidity = jest.fn();
      const reportValidity = jest.fn();

      validateField(
        {
          _f: {
            name: 'test',
            ref: {
              setCustomValidity,
              reportValidity,
              name: 'test',
              value: 'test',
            },
            value: 'test',
            required: true,
            mount: true,
          },
        },
        new Set(),
        {
          test: 'test',
        },
        false,
        true,
      );

      expect(setCustomValidity).toHaveBeenCalledWith('');
      expect(reportValidity).toHaveBeenCalled();
    });

    it('should abort validation early when input is disabled', async () => {
      expect(
        await validateField(
          {
            _f: {
              name: 'test',
              ref: {
                name: 'test',
                value: '',
              },
              value: '',
              required: 'something is wrong',
              disabled: true,
            },
          },
          new Set(),
          {
            test: '',
          },
          false,
        ),
      ).toEqual({});
    });
